#include <stdio.h>
#include <math.h>
typedef struct{float x,y,z;}Vec;
static float ss(float x){float r;__asm__("sqrtss %1,%0":"=x"(r):"x"(x));return r;}
static Vec va(Vec a,Vec b){return(Vec){a.x+b.x,a.y+b.y,a.z+b.z};}
static Vec vs(Vec a,Vec b){return(Vec){a.x-b.x,a.y-b.y,a.z-b.z};}
static Vec vm(Vec a,float s){return(Vec){a.x*s,a.y*s,a.z*s};}
static float vd(Vec a,Vec b){return a.x*b.x+a.y*b.y+a.z*b.z;}
static Vec vn(Vec a){float l=ss(vd(a,a));return(Vec){a.x/l,a.y/l,a.z/l};}
static Vec vrn(Vec a){float l=ss((a.z*a.z+a.y*a.y)+a.x*a.x);return(Vec){a.x/l,a.y/l,a.z/l};}
int sh(Vec ro,Vec rd,Vec c,float r,float*t){
Vec oc=vs(ro,c);
float a=vd(rd,rd),hb=vd(oc,rd),cc=(oc.y*oc.y+oc.x*oc.x)+oc.z*oc.z-r*r;
float tb=hb+hb,disc=tb*tb-4.0f*a*cc;
if(disc<0)return 0;
double ds=sqrt((double)disc),n2b=(double)(-tb),d2a=(double)(a+a);
float t0=(float)((n2b-ds)/d2a);
if(t0<0.001f)t0=(float)((n2b+ds)/d2a);
if(t0<0.001f)return 0;
*t=t0;return 1;
}
int main(){
int i=432,j=300;
float u=(float)i/799.0f*8.0f/3.0f-4.0f/3.0f;
float v=2.0f*(1.0f-(float)j/599.0f)-1.0f;
Vec rd=vrn((Vec){u,v,-1});Vec ro=(Vec){0,0,0};
Vec sc=(Vec){0,-0.5f,-5};float sr=1.0f;
float ts;int hs=sh(ro,rd,sc,sr,&ts);
printf("u=%a v=%a rd=(%a,%a,%a) ts=%a hs=%d\n",u,v,rd.x,rd.y,rd.z,ts,hs);
Vec p=va(ro,vm(rd,ts));
Vec n=vn(vs(p,sc));
Vec ld=vn((Vec){1,1,-1});
float dot1=n.x*ld.x+(n.y*ld.y+n.z*ld.z);
float dot2=(n.x*ld.x+n.y*ld.y)+n.z*ld.z;
float dot3=n.z*ld.z+(n.x*ld.x+n.y*ld.y);
float dot4=vd(n,ld);
printf("p=(%a,%a,%a) n=(%a,%a,%a) ld=(%a,%a,%a)\n",p.x,p.y,p.z,n.x,n.y,n.z,ld.x,ld.y,ld.z);
printf("dot1=%a dot2=%a dot3=%a dot4=%a\n",dot1,dot2,dot3,dot4);
float df=(float)fmax(0.0,(double)dot2);
float in=0.2f+0.8f*df;
printf("df=%a in=%a 255.99*in=%a int=%d\n",df,in,in*255.99f,(int)(in*255.99f));
return 0;
}
CEOF
